16	type campaignHandler struct {
17		pool        *pgxpool.Pool
18		authService *auth.Service
19	}
20	
21	func registerCampaignRoutes(r *gin.Engine, authService *auth.Service, pool *pgxpool.Pool) {
22		h := &campaignHandler{pool: pool, authService: authService}
23	
24		read := r.Group("/api")
25		read.Use(requireSession(authService), enforceForcePasswordChange(), requireRoles(authService, allSystemRoles()...))
26		{
27			read.GET("/campaigns", h.listCampaigns)
28			read.GET("/campaigns/:id", h.getCampaign)
29			read.GET("/campaigns/:id/tasks", h.listCampaignTasks)
30			read.GET("/tasks/:id", h.getTask)
31		}
32	
33		write := r.Group("/api")
34		write.Use(requireSession(authService), enforceForcePasswordChange(), requireRoles(authService, auth.RoleFacilityAdmin))
35		{
36			write.POST("/campaigns", h.createCampaign)
37			write.PATCH("/campaigns/:id", h.patchCampaign)
38			write.DELETE("/campaigns/:id", h.deleteCampaign)
39			write.POST("/campaigns/:id/tasks", h.createTask)
40			write.PATCH("/tasks/:id", h.patchTask)
41			write.DELETE("/tasks/:id", h.deleteTask)
42			write.POST("/tasks/:id/complete", h.completeTask)
43		}
44	}
45	
46	func (h *campaignHandler) listCampaigns(c *gin.Context) {
47		rows, err := h.pool.Query(c.Request.Context(), `
48			SELECT id::text, title, description, COALESCE(target_role,''), created_by::text, created_at, updated_at
49			FROM campaigns
50			ORDER BY created_at DESC
51		`)
52		if err != nil {
53			abortAPIError(c, 500, "INTERNAL_ERROR", "internal server error")
54			return
55		}
56		defer rows.Close()
57		out := make([]gin.H, 0)
58		for rows.Next() {
59			var id, title, description, targetRole string
60			var createdBy *string
61			var createdAt, updatedAt time.Time
62			if err := rows.Scan(&id, &title, &description, &targetRole, &createdBy, &createdAt, &updatedAt); err != nil {
63				abortAPIError(c, 500, "INTERNAL_ERROR", "internal server error")
64				return
65			}
66			item := gin.H{"id": id, "title": title, "description": description, "created_at": createdAt.UTC().Format(timeRFC3339), "updated_at": updatedAt.UTC().Format(timeRFC3339)}
67			if targetRole != "" {
68				item["target_role"] = targetRole
69			}
70			if createdBy != nil {
71				item["created_by"] = *createdBy
72			}
73			out = append(out, item)
74		}
75		c.JSON(http.StatusOK, out)
76	}
77	
78	func (h *campaignHandler) createCampaign(c *gin.Context) {
79		var b struct {
80			Title       string  `json:"title"`
81			Description string  `json:"description"`
82			TargetRole  *string `json:"target_role"`
83		}
84		if c.ShouldBindJSON(&b) != nil || strings.TrimSpace(b.Title) == "" {
85			abortAPIError(c, 400, "VALIDATION_ERROR", "invalid request body")
86			return
87		}
88		actor, _ := getCurrentUser(c)
89		var id string
90		err := h.pool.QueryRow(c.Request.Context(), `
91			INSERT INTO campaigns(title, description, target_role, created_by)
92			VALUES ($1, $2, NULLIF($3,''), $4::uuid)
93			RETURNING id::text
94		`, strings.TrimSpace(b.Title), strings.TrimSpace(b.Description), strings.TrimSpace(valueOrEmpty(b.TargetRole)), actor.ID).Scan(&id)
95		if err != nil {
96			abortAPIError(c, 500, "INTERNAL_ERROR", "internal server error")
97			return
98		}
99		_ = h.authService.WriteAuditLog(c.Request.Context(), &actor.ID, "campaign_create", "campaign", &id, map[string]any{"title": b.Title})
100		c.JSON(http.StatusCreated, gin.H{"id": id, "title": strings.TrimSpace(b.Title), "description": strings.TrimSpace(b.Description), "target_role": strings.TrimSpace(valueOrEmpty(b.TargetRole))})
101	}
102	
103	func (h *campaignHandler) getCampaign(c *gin.Context) {
104		var id, title, description, targetRole string
105		var createdBy *string
106		var createdAt, updatedAt time.Time
107		err := h.pool.QueryRow(c.Request.Context(), `
108			SELECT id::text, title, description, COALESCE(target_role,''), created_by::text, created_at, updated_at
109			FROM campaigns WHERE id=$1::uuid
110		`, c.Param("id")).Scan(&id, &title, &description, &targetRole, &createdBy, &createdAt, &updatedAt)
111		if err != nil {
112			if errors.Is(err, pgx.ErrNoRows) {
113				abortAPIError(c, 404, "NOT_FOUND", "resource not found")
114				return
115			}
116			abortAPIError(c, 500, "INTERNAL_ERROR", "internal server error")
117			return
118		}
119		out := gin.H{"id": id, "title": title, "description": description, "created_at": createdAt.UTC().Format(timeRFC3339), "updated_at": updatedAt.UTC().Format(timeRFC3339)}
120		if targetRole != "" {
121			out["target_role"] = targetRole
122		}
123		if createdBy != nil {
124			out["created_by"] = *createdBy
125		}
126		c.JSON(http.StatusOK, out)
127	}
