129	func (h *campaignHandler) patchCampaign(c *gin.Context) {
130		var b struct {
131			Title       *string `json:"title"`
132			Description *string `json:"description"`
133			TargetRole  *string `json:"target_role"`
134		}
135		if c.ShouldBindJSON(&b) != nil {
136			abortAPIError(c, 400, "VALIDATION_ERROR", "invalid request body")
137			return
138		}
139		_, err := h.pool.Exec(c.Request.Context(), `
140			UPDATE campaigns
141			SET title=COALESCE(NULLIF($2,''), title),
142				description=COALESCE($3, description),
143				target_role=COALESCE($4, target_role),
144				updated_at=now()
145			WHERE id=$1::uuid
146		`, c.Param("id"), strings.TrimSpace(valueOrEmpty(b.Title)), b.Description, b.TargetRole)
147		if err != nil {
148			abortAPIError(c, 500, "INTERNAL_ERROR", "internal server error")
149			return
150		}
151		c.JSON(http.StatusOK, gin.H{"message": "updated"})
