163	func (h *campaignHandler) listCampaignTasks(c *gin.Context) {
164		rows, err := h.pool.Query(c.Request.Context(), `
165			SELECT id::text, campaign_id::text, description, deadline, reminder_interval_minutes, completed_at, last_reminder_at, created_at, updated_at
166			FROM tasks
167			WHERE campaign_id=$1::uuid
168			ORDER BY created_at DESC
169		`, c.Param("id"))
170		if err != nil {
171			abortAPIError(c, 500, "INTERNAL_ERROR", "internal server error")
172			return
173		}
174		defer rows.Close()
175		items := make([]gin.H, 0)
176		for rows.Next() {
177			items = append(items, mustTaskRow(c, rows))
178		}
179		c.JSON(http.StatusOK, items)
