182	func (h *campaignHandler) createTask(c *gin.Context) {
183		var b struct {
184			Description             string `json:"description"`
185			Deadline                string `json:"deadline"`
186			ReminderIntervalMinutes int    `json:"reminder_interval_minutes"`
187		}
188		if c.ShouldBindJSON(&b) != nil || strings.TrimSpace(b.Description) == "" {
189			abortAPIError(c, 400, "VALIDATION_ERROR", "invalid request body")
190			return
191		}
192		interval := b.ReminderIntervalMinutes
193		if interval <= 0 {
194			interval = 60
195		}
196		var deadline any
197		if strings.TrimSpace(b.Deadline) != "" {
198			d, err := time.Parse(time.RFC3339, b.Deadline)
199			if err != nil {
200				abortAPIError(c, 400, "VALIDATION_ERROR", "deadline must be RFC3339")
201				return
202			}
203			deadline = d.UTC()
204		}
205		actor, _ := getCurrentUser(c)
206		var id string
207		err := h.pool.QueryRow(c.Request.Context(), `
208			INSERT INTO tasks(campaign_id, description, deadline, reminder_interval_minutes, created_by)
209			VALUES ($1::uuid, $2, $3, $4, $5::uuid)
210			RETURNING id::text
211		`, c.Param("id"), strings.TrimSpace(b.Description), deadline, interval, actor.ID).Scan(&id)
212		if err != nil {
213			abortAPIError(c, 500, "INTERNAL_ERROR", "internal server error")
214			return
215		}
216		_ = h.authService.WriteAuditLog(c.Request.Context(), &actor.ID, "task_create", "task", &id, map[string]any{"campaign_id": c.Param("id")})
217		c.JSON(http.StatusCreated, gin.H{"id": id, "campaign_id": c.Param("id"), "description": strings.TrimSpace(b.Description), "reminder_interval_minutes": interval})
218	}
219	
220	func (h *campaignHandler) getTask(c *gin.Context) {
221		row := h.pool.QueryRow(c.Request.Context(), `
222			SELECT id::text, campaign_id::text, description, deadline, reminder_interval_minutes, completed_at, last_reminder_at, created_at, updated_at
223			FROM tasks
224			WHERE id=$1::uuid
225		`, c.Param("id"))
226		var id, campaignID, description string
227		var deadline, completedAt, lastReminderAt *time.Time
228		var reminderInterval int
229		var createdAt, updatedAt time.Time
230		err := row.Scan(&id, &campaignID, &description, &deadline, &reminderInterval, &completedAt, &lastReminderAt, &createdAt, &updatedAt)
231		if err != nil {
232			if errors.Is(err, pgx.ErrNoRows) {
233				abortAPIError(c, 404, "NOT_FOUND", "resource not found")
234				return
235			}
236			abortAPIError(c, 500, "INTERNAL_ERROR", "internal server error")
237			return
238		}
239		out := taskJSON(id, campaignID, description, deadline, reminderInterval, completedAt, lastReminderAt, createdAt, updatedAt)
240		c.JSON(http.StatusOK, out)
241	}
242	
243	func (h *campaignHandler) patchTask(c *gin.Context) {
244		var b struct {
245			Description             *string `json:"description"`
246			Deadline                *string `json:"deadline"`
247			ReminderIntervalMinutes *int    `json:"reminder_interval_minutes"`
248		}
249		if c.ShouldBindJSON(&b) != nil {
250			abortAPIError(c, 400, "VALIDATION_ERROR", "invalid request body")
251			return
252		}
253		var deadline any
254		if b.Deadline != nil {
255			if strings.TrimSpace(*b.Deadline) == "" {
256				deadline = nil
257			} else {
258				d, err := time.Parse(time.RFC3339, strings.TrimSpace(*b.Deadline))
259				if err != nil {
260					abortAPIError(c, 400, "VALIDATION_ERROR", "deadline must be RFC3339")
261					return
262				}
263				deadline = d.UTC()
264			}
265		}
266		var interval any
267		if b.ReminderIntervalMinutes != nil {
268			if *b.ReminderIntervalMinutes <= 0 {
269				abortAPIError(c, 400, "VALIDATION_ERROR", "reminder_interval_minutes must be positive")
270				return
271			}
272			interval = *b.ReminderIntervalMinutes
273		}
274		_, err := h.pool.Exec(c.Request.Context(), `
275			UPDATE tasks
276			SET description=COALESCE(NULLIF($2,''), description),
277				deadline=COALESCE($3, deadline),
278				reminder_interval_minutes=COALESCE($4, reminder_interval_minutes),
279				updated_at=now()
280			WHERE id=$1::uuid
281		`, c.Param("id"), valueOrNilString(b.Description), deadline, interval)
282		if err != nil {
283			abortAPIError(c, 500, "INTERNAL_ERROR", "internal server error")
284			return
285		}
286		c.JSON(http.StatusOK, gin.H{"message": "updated"})
287	}
288	
289	func (h *campaignHandler) deleteTask(c *gin.Context) {
290		_, err := h.pool.Exec(c.Request.Context(), `DELETE FROM tasks WHERE id=$1::uuid`, c.Param("id"))
291		if err != nil {
292			abortAPIError(c, 500, "INTERNAL_ERROR", "internal server error")
293			return
294		}
295		c.Status(http.StatusNoContent)
296	}
297	
298	func (h *campaignHandler) completeTask(c *gin.Context) {
299		actor, _ := getCurrentUser(c)
300		taskID := c.Param("id")
301		_, err := h.pool.Exec(c.Request.Context(), `
302			UPDATE tasks
303			SET completed_at=now(), completed_by=$2::uuid, updated_at=now()
304			WHERE id=$1::uuid
305		`, taskID, actor.ID)
306		if err != nil {
307			abortAPIError(c, 500, "INTERNAL_ERROR", "internal server error")
308			return
309		}
310		_ = h.authService.WriteAuditLog(c.Request.Context(), &actor.ID, "task_complete", "task", &taskID, map[string]any{})
311		h.getTask(c)
312	}
313	
314	func valueOrEmpty(v *string) string {
315		if v == nil {
316			return ""
317		}
318		return strings.TrimSpace(*v)
319	}
320	
321	func valueOrNilString(v *string) any {
322		if v == nil {
323			return nil
324		}
325		trimmed := strings.TrimSpace(*v)
326		if trimmed == "" {
327			return nil
328		}
329		return trimmed
330	}
331	
332	func mustTaskRow(c *gin.Context, rows pgx.Rows) gin.H {
333		var id, campaignID, description string
334		var deadline, completedAt, lastReminderAt *time.Time
335		var reminderInterval int
336		var createdAt, updatedAt time.Time
337		if err := rows.Scan(&id, &campaignID, &description, &deadline, &reminderInterval, &completedAt, &lastReminderAt, &createdAt, &updatedAt); err != nil {
338			abortAPIError(c, 500, "INTERNAL_ERROR", "internal server error")
339			return gin.H{}
340		}
341		return taskJSON(id, campaignID, description, deadline, reminderInterval, completedAt, lastReminderAt, createdAt, updatedAt)
342	}
343	
344	func taskJSON(id, campaignID, description string, deadline *time.Time, reminderInterval int, completedAt, lastReminderAt *time.Time, createdAt, updatedAt time.Time) gin.H {
345		out := gin.H{
346			"id":                        id,
347			"campaign_id":               campaignID,
348			"description":               description,
349			"reminder_interval_minutes": reminderInterval,
350			"created_at":                createdAt.UTC().Format(timeRFC3339),
351			"updated_at":                updatedAt.UTC().Format(timeRFC3339),
352		}
353		if deadline != nil {
354			out["deadline"] = deadline.UTC().Format(timeRFC3339)
355		}
356		if completedAt != nil {
357			out["completed_at"] = completedAt.UTC().Format(timeRFC3339)
358		}
359		if lastReminderAt != nil {
360			out["last_reminder_at"] = lastReminderAt.UTC().Format(timeRFC3339)
361		}
362		return out
363	}
