13	func TestCampaignTaskReminderStopsAfterComplete(t *testing.T) {
14		env := setupAuthAPIEnv(t)
15		admin := loginAs(t, env, "admin", "AdminPass1234")
16	
17		topics := apiRequest(t, env.r, http.MethodGet, "/api/notification-topics", nil, admin)
18		logStep(t, "GET", "/api/notification-topics", topics.Code, topics.Body.String())
19		if topics.Code != http.StatusOK {
20			t.Fatalf("topics failed: %d %s", topics.Code, topics.Body.String())
21		}
22		topicID := topicIDByName(t, topics.Body.String(), "task_reminder")
23	
24		sub := apiRequest(t, env.r, http.MethodPost, "/api/notification-topics/"+topicID+"/subscribe", nil, admin)
25		logStep(t, "POST", "/api/notification-topics/:id/subscribe", sub.Code, sub.Body.String())
26		if sub.Code != http.StatusOK {
27			t.Fatalf("subscribe failed: %d %s", sub.Code, sub.Body.String())
28		}
29	
30		createCampaign := apiRequest(t, env.r, http.MethodPost, "/api/campaigns", map[string]any{
31			"title":       "Ops Checks",
32			"description": "nightly checks",
33		}, admin)
34		logStep(t, "POST", "/api/campaigns", createCampaign.Code, createCampaign.Body.String())
35		if createCampaign.Code != http.StatusCreated {
36			t.Fatalf("create campaign failed: %d %s", createCampaign.Code, createCampaign.Body.String())
37		}
38		campaignID := extractID(t, createCampaign.Body.String())
39	
40		createTask := apiRequest(t, env.r, http.MethodPost, "/api/campaigns/"+campaignID+"/tasks", map[string]any{
41			"description":               "Check gate A",
42			"deadline":                  time.Now().UTC().Add(-2 * time.Hour).Format(time.RFC3339),
43			"reminder_interval_minutes": 1,
44		}, admin)
45		logStep(t, "POST", "/api/campaigns/:id/tasks", createTask.Code, createTask.Body.String())
46		if createTask.Code != http.StatusCreated {
47			t.Fatalf("create task failed: %d %s", createTask.Code, createTask.Body.String())
48		}
49		taskID := extractID(t, createTask.Body.String())
50	
51		processor := campaigns.NewService(env.pool)
52		if err := processor.ProcessDueTaskReminders(context.Background(), time.Now().UTC()); err != nil {
53			t.Fatalf("process reminders failed: %v", err)
54		}
55	
56		listNotifications := apiRequest(t, env.r, http.MethodGet, "/api/notifications", nil, admin)
57		logStep(t, "GET", "/api/notifications", listNotifications.Code, listNotifications.Body.String())
58		if listNotifications.Code != http.StatusOK || !strings.Contains(listNotifications.Body.String(), "Task reminder") {
59			t.Fatalf("expected task reminder notification, got %d %s", listNotifications.Code, listNotifications.Body.String())
60		}
61	
62		var beforeCount int
63		err := env.pool.QueryRow(context.Background(), `
64			SELECT COUNT(*) FROM notification_jobs WHERE payload->>'task_id'=$1
65		`, taskID).Scan(&beforeCount)
66		if err != nil {
67			t.Fatalf("count reminder jobs before complete: %v", err)
68		}
69		if beforeCount == 0 {
70			t.Fatal("expected at least one reminder job before task completion")
71		}
72	
73		complete := apiRequest(t, env.r, http.MethodPost, "/api/tasks/"+taskID+"/complete", nil, admin)
74		logStep(t, "POST", "/api/tasks/:id/complete", complete.Code, complete.Body.String())
75		if complete.Code != http.StatusOK {
76			t.Fatalf("complete task failed: %d %s", complete.Code, complete.Body.String())
77		}
78	
79		if err := processor.ProcessDueTaskReminders(context.Background(), time.Now().UTC().Add(3*time.Minute)); err != nil {
80			t.Fatalf("process reminders after complete failed: %v", err)
81		}
82	
83		var afterCount int
84		err = env.pool.QueryRow(context.Background(), `
85			SELECT COUNT(*) FROM notification_jobs WHERE payload->>'task_id'=$1
86		`, taskID).Scan(&afterCount)
87		if err != nil {
88			t.Fatalf("count reminder jobs after complete: %v", err)
89		}
90		if afterCount != beforeCount {
91			t.Fatalf("expected reminder job count unchanged after completion, before=%d after=%d", beforeCount, afterCount)
92		}
93	}
