95	func TestCampaignAndTaskCRUDEndpoints(t *testing.T) {
96		env := setupAuthAPIEnv(t)
97		admin := loginAs(t, env, "admin", "AdminPass1234")
98	
99		createCampaign := apiRequest(t, env.r, http.MethodPost, "/api/campaigns", map[string]any{
100			"title":       "Morning Ops",
101			"description": "open checklist",
102		}, admin)
103		logStep(t, "POST", "/api/campaigns", createCampaign.Code, createCampaign.Body.String())
104		if createCampaign.Code != http.StatusCreated {
105			t.Fatalf("create campaign failed: %d %s", createCampaign.Code, createCampaign.Body.String())
106		}
107		campaignID := extractID(t, createCampaign.Body.String())
108	
109		getCampaign := apiRequest(t, env.r, http.MethodGet, "/api/campaigns/"+campaignID, nil, admin)
110		logStep(t, "GET", "/api/campaigns/:id", getCampaign.Code, getCampaign.Body.String())
111		if getCampaign.Code != http.StatusOK {
112			t.Fatalf("get campaign failed: %d %s", getCampaign.Code, getCampaign.Body.String())
113		}
114	
115		patchCampaign := apiRequest(t, env.r, http.MethodPatch, "/api/campaigns/"+campaignID, map[string]any{
116			"description": "open checklist updated",
117		}, admin)
118		logStep(t, "PATCH", "/api/campaigns/:id", patchCampaign.Code, patchCampaign.Body.String())
119		if patchCampaign.Code != http.StatusOK {
120			t.Fatalf("patch campaign failed: %d %s", patchCampaign.Code, patchCampaign.Body.String())
121		}
122	
123		createTask := apiRequest(t, env.r, http.MethodPost, "/api/campaigns/"+campaignID+"/tasks", map[string]any{
124			"description":               "Check zone lights",
125			"reminder_interval_minutes": 10,
126		}, admin)
127		logStep(t, "POST", "/api/campaigns/:id/tasks", createTask.Code, createTask.Body.String())
128		if createTask.Code != http.StatusCreated {
129			t.Fatalf("create task failed: %d %s", createTask.Code, createTask.Body.String())
