131		taskID := extractID(t, createTask.Body.String())
132	
133		listTasks := apiRequest(t, env.r, http.MethodGet, "/api/campaigns/"+campaignID+"/tasks", nil, admin)
134		logStep(t, "GET", "/api/campaigns/:id/tasks", listTasks.Code, listTasks.Body.String())
135		if listTasks.Code != http.StatusOK || !strings.Contains(listTasks.Body.String(), taskID) {
136			t.Fatalf("list tasks failed: %d %s", listTasks.Code, listTasks.Body.String())
137		}
138	
139		patchTask := apiRequest(t, env.r, http.MethodPatch, "/api/tasks/"+taskID, map[string]any{
140			"description": "Check zone lights and signage",
141		}, admin)
142		logStep(t, "PATCH", "/api/tasks/:id", patchTask.Code, patchTask.Body.String())
143		if patchTask.Code != http.StatusOK {
144			t.Fatalf("patch task failed: %d %s", patchTask.Code, patchTask.Body.String())
145		}
146	
147		getTask := apiRequest(t, env.r, http.MethodGet, "/api/tasks/"+taskID, nil, admin)
148		logStep(t, "GET", "/api/tasks/:id", getTask.Code, getTask.Body.String())
149		if getTask.Code != http.StatusOK || !strings.Contains(getTask.Body.String(), "signage") {
150			t.Fatalf("get task failed: %d %s", getTask.Code, getTask.Body.String())
151		}
