173	func apiRequest(t *testing.T, r http.Handler, method, path string, body any, cookie *http.Cookie) *httptest.ResponseRecorder {
174		t.Helper()
175	
176		var reqBody io.Reader
177		if body != nil {
178			b, err := json.Marshal(body)
179			if err != nil {
180				t.Fatalf("marshal body: %v", err)
181			}
182			reqBody = bytes.NewReader(b)
183		}
184	
185		req := httptest.NewRequest(method, path, reqBody)
186		if body != nil {
187			req.Header.Set("Content-Type", "application/json")
188		}
189		if cookie != nil {
190			req.AddCookie(cookie)
191		}
192	
193		w := httptest.NewRecorder()
194		r.ServeHTTP(w, req)
195		return w
196	}
