21	func (s *Service) ProcessDueTaskReminders(ctx context.Context, now time.Time) error {
22		tx, err := s.pool.Begin(ctx)
23		if err != nil {
24			return err
25		}
26		defer tx.Rollback(ctx)
27	
28		var topicID string
29		err = tx.QueryRow(ctx, `SELECT id::text FROM notification_topics WHERE name='task_reminder' LIMIT 1`).Scan(&topicID)
30		if err != nil {
31			return err
32		}
33	
34		tasksRows, err := tx.Query(ctx, `
35			SELECT t.id::text, t.description
36			FROM tasks t
37			WHERE t.completed_at IS NULL
38			  AND t.deadline IS NOT NULL
39			  AND t.deadline <= $1
40			  AND (
41				  t.last_reminder_at IS NULL
42				  OR t.last_reminder_at <= $1 - ((t.reminder_interval_minutes::text || ' minutes')::interval)
43			  )
44			ORDER BY t.deadline ASC
45			LIMIT 200
46		`, now.UTC())
47		if err != nil {
48			return err
49		}
50		defer tasksRows.Close()
51	
52		type dueTask struct {
53			ID          string
54			Description string
55		}
56		tasks := make([]dueTask, 0)
57		for tasksRows.Next() {
58			var t dueTask
59			if err := tasksRows.Scan(&t.ID, &t.Description); err != nil {
60				return err
61			}
62			tasks = append(tasks, t)
63		}
64	
65		usersRows, err := tx.Query(ctx, `SELECT DISTINCT user_id::text FROM notification_subscriptions WHERE topic_id=$1::uuid`, topicID)
66		if err != nil {
67			return err
68		}
69		defer usersRows.Close()
70		userIDs := make([]string, 0)
71		for usersRows.Next() {
72			var userID string
73			if err := usersRows.Scan(&userID); err != nil {
74				return err
75			}
76			userIDs = append(userIDs, userID)
77		}
78	
79		for _, task := range tasks {
80			for _, userID := range userIDs {
81				var notificationID string
82				err := tx.QueryRow(ctx, `
83					INSERT INTO notifications(user_id, topic_id, title, body, created_at)
84					VALUES ($1::uuid, $2::uuid, 'Task reminder', $3, $4)
85					RETURNING id::text
86				`, userID, topicID, task.Description, now.UTC()).Scan(&notificationID)
87				if err != nil {
88					return err
89				}
90	
91				payload, _ := json.Marshal(map[string]any{"recipient": userID, "task_id": task.ID})
92				_, err = tx.Exec(ctx, `
93					INSERT INTO notification_jobs(notification_id, user_id, topic_id, channel, status, attempt_count, payload, created_at, updated_at)
94					VALUES ($1::uuid, $2::uuid, $3::uuid, 'in_app', 'pending', 0, $4::jsonb, $5, $5)
95				`, notificationID, userID, topicID, string(payload), now.UTC())
96				if err != nil {
97					return err
98				}
99			}
100	
101			_, err = tx.Exec(ctx, `UPDATE tasks SET last_reminder_at=$2, updated_at=$2 WHERE id=$1::uuid`, task.ID, now.UTC())
102			if err != nil {
103				return err
104			}
105		}
106	
107		return tx.Commit(ctx)
108	}
109	
110	func StartReminderScheduler(ctx context.Context, logger *slog.Logger, service *Service) {
111		ticker := time.NewTicker(1 * time.Minute)
112		defer ticker.Stop()
113		for {
114			select {
115			case <-ctx.Done():
116				return
117			case now := <-ticker.C:
118				if err := service.ProcessDueTaskReminders(ctx, now.UTC()); err != nil && err != pgx.ErrNoRows {
119					logger.Error("task reminder processor failed", "error", err)
120				}
121			}
122		}
123	}
